// // This module calculates the quotient and remainder of two 2-bit numbers. If the divisor is non-zero, it returns the correct values; otherwise, it sets both outputs to 2'b00.
module divider_2bit (
    input [1:0] A, // Dividend
    input [1:0] B, // Divisor
    output reg [1:0] Quotient, // Quotient
    output reg [1:0] Remainder // Remainder
);

always @(*) begin
    if (B == 2'b00) begin
        Quotient = 2'b00;
        Remainder = 2'b00;
    end else begin
        Quotient = A / B;
        Remainder = A % B;
    end
end

endmodule
